// chainNodeList returns a text representation of node IDs with arrows
func chainNodeList(nodes []model.ChainNode) string {
	s := ""
	for i, n := range nodes {
		if i > 0 {
			s += " → "
		}
		s += n.ID
	}
	return s
}

